-- Acts 9: The Conversion of Saul and the Widening Ministry of Peter

-- 1. Chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 9,
  'Acts 9 is the hinge chapter of Luke''s second volume. The relentless persecutor Saul of Tarsus, breathing out "threatenings and slaughter" against the disciples, is met on the road to Damascus by the risen Christ himself. A blinding light, a heavenly voice, and a single identifying question — "Why persecutest thou me?" — together reveal that to touch the church is to touch the glorified Lord. Saul is led helpless into Damascus, where after three days of blind fasting, the reluctant but obedient disciple Ananias is sent by vision to baptize and commission him. Saul is immediately and publicly identified as God''s "chosen vessel" to bear the name before Gentiles, kings, and the children of Israel, and just as suddenly begins preaching Jesus as the Son of God in the very synagogues he came to purge. The astonishing reversal provokes a plot against his life, from which the Damascus disciples rescue him by lowering him in a basket through the city wall. In Jerusalem, Barnabas brokers his acceptance by the apostles. Saul then debates the Hellenists and is sent away to Tarsus for his own safety. Luke records that "then had the churches rest" — the fiercest opponent converted, the persecuting sword broken, and the gospel now advancing in peace and comfort of the Holy Ghost. The chapter closes with Peter''s ministry at Lydda (healing the paralytic Aeneas) and at Joppa (raising the beloved disciple Dorcas from the dead), appointed episodes that prepare the reader for the decisive breakthrough to the Gentiles in chapters 10-11.',
  'The Risen Christ Arrests His Persecutor and Widens His Apostolic Witness',
  'σκεῦος ἐκλογῆς',
  'chosen vessel, instrument of election',
  '["Saul''s conversion on the Damascus road (vv.1-9)", "Ananias'' vision and Saul''s baptism and commissioning (vv.10-19a)", "Saul preaches Christ in Damascus and escapes a plot (vv.19b-25)", "Saul received by the Jerusalem church through Barnabas and sent to Tarsus (vv.26-31)", "Peter heals Aeneas at Lydda (vv.32-35)", "Peter raises Dorcas at Joppa (vv.36-43)"]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

-- 2. Verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And Saul, yet breathing out threatenings and slaughter against the disciples of the Lord, went unto the high priest,',
   'Ὁ δὲ Σαῦλος ἔτι ἐμπνέων ἀπειλῆς καὶ φόνου εἰς τοὺς μαθητὰς τοῦ κυρίου, προσελθὼν τῷ ἀρχιερεῖ',
   'Ho de Saulos eti empneōn apeilēs kai phonou eis tous mathētas tou kyriou, proselthōn tō archierei',
   '"Empneōn" ("breathing out") is an imperfect participle: threat and murder are the very air Saul exhales. Luke paints persecution as Saul''s respiratory rhythm, not an occasional activity. The high priest in AD 33-34 was likely Caiaphas (or his successor Theophilus); Saul operates under Sanhedrin authority that still assumed jurisdiction over synagogues of the diaspora.',
   'Unconverted religious zeal can be more lethal than pagan hostility. Saul''s pre-conversion life shows that sincere devotion to Mosaic tradition, when not submitted to Christ, runs straight at the church of God.'),
  (2, 'And desired of him letters to Damascus to the synagogues, that if he found any of this way, whether they were men or women, he might bring them bound unto Jerusalem.',
   'ᾐτήσατο παρ’ αὐτοῦ ἐπιστολὰς εἰς Δαμασκὸν πρὸς τὰς συναγωγάς, ὅπως ἐάν τινας εὕρῃ τῆς ὁδοῦ ὄντας, ἄνδρας τε καὶ γυναῖκας, δεδεμένους ἀγάγῃ εἰς Ἰερουσαλήμ.',
   'Ētēsato par'' autou epistolas eis Damaskon pros tas synagōgas, hopōs ean tinas heurē tēs hodou ontas, andras te kai gynaikas, dedemenous agagē eis Ierousalēm.',
   'Damascus lay about 135 miles north of Jerusalem; Jewish colonies there were sizable and commercially important. "Tēs hodou" ("of the Way") is the earliest self-designation of Christians (cf. 19:9; 22:4; 24:14), reflecting Jesus'' self-identification as "the way" (John 14:6). Saul''s warrant targets "men and women" — the church''s female disciples were not spared.',
   'Christianity is not a sect within Judaism but "the Way" — the covenant path fulfilled in Jesus. The title carries missional and moral freight: to follow Christ is to walk a defined road, not merely to hold an opinion.'),
  (3, 'And as he journeyed, he came near Damascus: and suddenly there shined round about him a light from heaven:',
   'ἐν δὲ τῷ πορεύεσθαι ἐγένετο αὐτὸν ἐγγίζειν τῇ Δαμασκῷ, ἐξαίφνης τε αὐτὸν περιήστραψεν φῶς ἐκ τοῦ οὐρανοῦ,',
   'En de tō poreuesthai egeneto auton engizein tē Damaskō, exaiphnēs te auton periēstrapsen phōs ek tou ouranou,',
   '"Exaiphnēs" ("suddenly") marks divine intrusion; "periēstrapsen" ("flashed around") is from the same root as "lightning" (astrapē) in Matthew 28:3. The manifestation of light "from heaven" surpasses Damascene noon sun (22:6; 26:13) — this is the unveiled glory of the risen Christ (cf. 2 Cor 4:6).',
   'The glory that blinded Saul is the same glory that now shines in Christian hearts by the gospel. Saul''s conversion experience is paradigmatic of all conversion: God who said "Let there be light" shines in the heart to reveal Christ.'),
  (4, 'And he fell to the earth, and heard a voice saying unto him, Saul, Saul, why persecutest thou me?',
   'καὶ πεσὼν ἐπὶ τὴν γῆν ἤκουσεν φωνὴν λέγουσαν αὐτῷ· Σαοὺλ Σαούλ, τί με διώκεις;',
   'Kai pesōn epi tēn gēn ēkousen phōnēn legousan autō; Saoul Saoul, ti me diōkeis?',
   'The doubled vocative "Saoul Saoul" (Hebraic form) echoes "Moses, Moses" (Exod 3:4), "Samuel, Samuel" (1 Sam 3:10), "Abraham, Abraham" (Gen 22:11) — divine summons in solemn repetition. "Me diōkeis" ("persecutest me") declares the mystical union of Christ with his church: whatever is done to his disciples is done to him (cf. Matt 25:40-45).',
   'Christ''s solidarity with his people is so complete that persecution of the church is persecution of the Lord himself. The doctrine of the union of Christ and the church is here revealed in a single question, and it grounds every theology of the body of Christ.'),
  (5, 'And he said, Who art thou, Lord? And the Lord said, I am Jesus whom thou persecutest: it is hard for thee to kick against the pricks.',
   'εἶπεν δέ· τίς εἶ, κύριε; ὁ δέ· ἐγώ εἰμι Ἰησοῦς ὃν σὺ διώκεις·',
   'Eipen de; tis ei, kyrie? Ho de; egō eimi Iēsous hon sy diōkeis.',
   'Saul''s "kyrie" is at first a generic address ("sir"), but it is about to become a confession. The answer "egō eimi Iēsous" shatters his theology: the crucified Galilean lives and speaks from heaven. The Textus Receptus adds "it is hard for thee to kick against the pricks" — a Greek proverb (cf. Euripides, Bacchae 795) for futile resistance to a higher power; it appears explicitly in 26:14.',
   'The identity of the risen Christ is the non-negotiable hinge of conversion. To say "Jesus" is the Lord of heavenly glory is to surrender every rival loyalty; no authentic Christianity begins anywhere else.'),
  (6, 'And he trembling and astonished said, Lord, what wilt thou have me to do? And the Lord said unto him, Arise, and go into the city, and it shall be told thee what thou must do.',
   'ἀλλὰ ἀνάστηθι καὶ εἴσελθε εἰς τὴν πόλιν, καὶ λαληθήσεταί σοι ὅ τί σε δεῖ ποιεῖν.',
   'Alla anastēthi kai eiselthe eis tēn polin, kai lalēthēsetai soi ho ti se dei poiein.',
   'The TR has Saul''s response, "trembling and astonished… Lord, what wilt thou have me to do?" (absent in the critical texts but echoed in 22:10). "Dei" ("must") is Luke''s recurring verb of divine necessity; Saul''s entire future is compressed into that one word. Notably, he receives no immediate mission — only the direction to walk obediently into the city and wait for instruction.',
   'Conversion begins as surrender to divine direction, not with comprehension of a calling. The risen Christ reserves the right to unfold his will step-by-step; the disciple''s first vocation is to rise, enter, and wait.'),
  (7, 'And the men which journeyed with him stood speechless, hearing a voice, but seeing no man.',
   'οἱ δὲ ἄνδρες οἱ συνοδεύοντες αὐτῷ εἱστήκεισαν ἐνεοί, ἀκούοντες μὲν τῆς φωνῆς, μηδένα δὲ θεωροῦντες.',
   'Hoi de andres hoi synodeuontes autō heistēkeisan eneoi, akouontes men tēs phōnēs, mēdena de theōrountes.',
   'The apparent tension with 22:9 ("they heard not the voice") is resolved by Greek grammar: here "phōnēs" (genitive) means they heard the sound; in 22:9 "phōnēn" (accusative) means they did not understand the message. Luke''s precision underscores that the encounter was not a subjective vision: external witnesses perceived the audible and visual phenomena without sharing the revelation.',
   'God authenticates his saving revelation with external, public evidence while reserving its saving content for the elect heart. Saul''s companions heard and saw, but only Saul met the Lord.'),
  (8, 'And Saul arose from the earth; and when his eyes were opened, he saw no man: but they led him by the hand, and brought him into Damascus.',
   'ἠγέρθη δὲ Σαῦλος ἀπὸ τῆς γῆς, ἀνεῳγμένων δὲ τῶν ὀφθαλμῶν αὐτοῦ οὐδὲν ἔβλεπεν· χειραγωγοῦντες δὲ αὐτὸν εἰσήγαγον εἰς Δαμασκόν.',
   'Ēgerthē de Saulos apo tēs gēs, aneōgmenōn de tōn ophthalmōn autou ouden eblepen; cheiragōgountes de auton eisēgagon eis Damaskon.',
   '"Cheiragōgountes" ("leading by the hand") is poignant — the proud Pharisee who came to lead prisoners bound now enters the city himself led like a child. The physical blindness mirrors his spiritual blindness (cf. 2 Cor 3:14-16); Christ removes both together.',
   'God humbles before he exalts. Saul''s literal groping is a visible parable of every sinner''s posture before grace: led by strangers into a city he does not know, awaiting a revelation he cannot summon.'),
  (9, 'And he was three days without sight, and neither did eat nor drink.',
   'καὶ ἦν ἡμέρας τρεῖς μὴ βλέπων, καὶ οὐκ ἔφαγεν οὐδὲ ἔπιεν.',
   'Kai ēn hēmeras treis mē blepōn, kai ouk ephagen oude epien.',
   'Three days of darkness and fasting evoke Jonah in the belly (Jon 1:17) and Jesus in the tomb (Matt 12:40). Saul experiences a micro-sabbatical of death before a call to new life. Total abstention from food and water — unusual even for fasting — reflects profound spiritual crisis and reorientation.',
   'Genuine conversion often involves a time of deep stillness in which self-reliance is broken before new life is given. God''s saving work presses down before it lifts up, stripping every prop from the soul he means to save.'),
  (10, 'And there was a certain disciple at Damascus, named Ananias; and to him said the Lord in a vision, Ananias. And he said, Behold, I am here, Lord.',
   'Ἦν δέ τις μαθητὴς ἐν Δαμασκῷ ὀνόματι Ἁνανίας, καὶ εἶπεν πρὸς αὐτὸν ἐν ὁράματι ὁ κύριος· Ἁνανία. ὁ δὲ εἶπεν· ἰδοὺ ἐγώ, κύριε.',
   'Ēn de tis mathētēs en Damaskō onomati Hananias, kai eipen pros auton en horamati ho kyrios; Hanania. Ho de eipen; idou egō, kyrie.',
   'Ananias ("Yahweh is gracious") is called simply "a disciple" — he is not an apostle, yet he mediates a pivotal moment in redemptive history. His answer "idou egō" ("behold, I") echoes Abraham (Gen 22:1), Moses (Exod 3:4), Samuel (1 Sam 3:4) — patriarchal responsiveness to divine call.',
   'God often performs decisive works of grace through obscure disciples. The history of redemption is punctuated by ordinary believers whose availability to the Lord is more significant than their public stature.'),
  (11, 'And the Lord said unto him, Arise, and go into the street which is called Straight, and enquire in the house of Judas for one called Saul, of Tarsus: for, behold, he prayeth,',
   'ὁ δὲ κύριος πρὸς αὐτόν· ἀναστὰς πορεύθητι ἐπὶ τὴν ῥύμην τὴν καλουμένην εὐθεῖαν καὶ ζήτησον ἐν οἰκίᾳ Ἰούδα Σαῦλον ὀνόματι Ταρσέα· ἰδοὺ γὰρ προσεύχεται,',
   'Ho de kyrios pros auton; anastas poreuthēti epi tēn rhymēn tēn kaloumenēn eutheian kai zētēson en oikia Iouda Saulon onomati Tarsea; idou gar proseuchetai,',
   'The "street called Straight" (Darb al-Mustaqim) still runs through Damascus today — a detail of striking local precision. "He prayeth" is the first evidence offered of Saul''s new orientation: Pharisaic prayer had been routine, but this prayer is different — a cry for mercy and revelation.',
   'Prayer is the native breath of the new creation. When a heart that formerly breathed threat begins to breathe supplication, God himself certifies the change.'),
  (12, 'And hath seen in a vision a man named Ananias coming in, and putting his hand on him, that he might receive his sight.',
   'καὶ εἶδεν ἄνδρα ἐν ὁράματι Ἁνανίαν ὀνόματι εἰσελθόντα καὶ ἐπιθέντα αὐτῷ τὰς χεῖρας ὅπως ἀναβλέψῃ.',
   'Kai eiden andra en horamati Hananian onomati eiselthonta kai epithenta autō tas cheiras hopōs anablepsē.',
   'Two visions converge: Christ arranges a mutual disclosure so that both Saul and Ananias may act in faith. Laying on of hands transmits no magical power but symbolizes identification, blessing, and the transfer of commission (cf. Num 27:18, Lev 1:4).',
   'Divine guidance in ministry is often confirmed by convergence of revelation in distinct believers. God rarely calls alone; he arranges the checks and corroborations of his body to protect his servants from both deception and timidity.'),
  (13, 'Then Ananias answered, Lord, I have heard by many of this man, how much evil he hath done to thy saints at Jerusalem:',
   'ἀπεκρίθη δὲ Ἁνανίας· κύριε, ἤκουσα ἀπὸ πολλῶν περὶ τοῦ ἀνδρὸς τούτου, ὅσα κακὰ τοῖς ἁγίοις σου ἐποίησεν ἐν Ἰερουσαλήμ·',
   'Apekrithē de Hananias; kyrie, ēkousa apo pollōn peri tou andros toutou, hosa kaka tois hagiois sou epoiēsen en Ierousalēm;',
   'Ananias''s candid pushback shows that the Lord does not demand blind obedience — the disciple may voice legitimate concern. "Tois hagiois sou" ("thy saints") is an early, tender Christian self-designation: believers are holy ones belonging to Christ. Saul''s notorious reputation had crossed the 135 miles to Damascus.',
   'Believers may bring their fears and objections honestly to God without forfeiting obedience. The spirit of Christianity is not unthinking compliance but dialogical trust that trusts even when it does not fully understand.'),
  (14, 'And here he hath authority from the chief priests to bind all that call on thy name.',
   'καὶ ὧδε ἔχει ἐξουσίαν παρὰ τῶν ἀρχιερέων δῆσαι πάντας τοὺς ἐπικαλουμένους τὸ ὄνομά σου.',
   'Kai hōde echei exousian para tōn archiereōn dēsai pantas tous epikaloumenous to onoma sou.',
   '"Tous epikaloumenous to onoma sou" ("those calling on thy name") is a covenantal designation rooted in Joel 2:32 (cf. Acts 2:21) and a functional definition of Christians: worshippers of Jesus by invocation. Saul''s mission was to arrest everyone who did this — a testimony that earliest Christians prayed to Jesus.',
   'Christians are known by their invocation of Christ''s name. Prayer to Jesus is not a later development but the defining identity marker of the earliest church, implying his full divine status.'),
  (15, 'But the Lord said unto him, Go thy way: for he is a chosen vessel unto me, to bear my name before the Gentiles, and kings, and the children of Israel:',
   'εἶπεν δὲ πρὸς αὐτὸν ὁ κύριος· πορεύου, ὅτι σκεῦος ἐκλογῆς ἐστίν μοι οὗτος τοῦ βαστάσαι τὸ ὄνομά μου ἐνώπιον ἐθνῶν τε καὶ βασιλέων υἱῶν τε Ἰσραήλ·',
   'Eipen de pros auton ho kyrios; poreuou, hoti skeuos eklogēs estin moi houtos tou bastasai to onoma mou enōpion ethnōn te kai basileōn huiōn te Israēl;',
   '"Skeuos eklogēs" ("vessel of election") — Paul himself will deploy vessel-imagery in Romans 9:21-23. Luke forecasts Paul''s entire career in one sentence: Gentiles (Antioch, Corinth, Ephesus, Rome), kings (Agrippa, Caesar), and children of Israel (every synagogue mission). The ordering places the Gentiles first, signaling Luke''s missiological heart.',
   'God''s election is not an abstract decree but a concrete appointment to bear the name of Christ into every stratum of humanity. Divine choice issues in apostolic mission; the doctrine of election grounds the urgency of evangelism.'),
  (16, 'For I will shew him how great things he must suffer for my name''s sake.',
   'ἐγὼ γὰρ ὑποδείξω αὐτῷ ὅσα δεῖ αὐτὸν ὑπὲρ τοῦ ὀνόματός μου παθεῖν.',
   'Egō gar hypodeixō autō hosa dei auton hyper tou onomatos mou pathein.',
   '"Hypodeixō" ("I will show") — Christ will personally school Saul in the curriculum of suffering. "Pathein" ("to suffer") is the same verb used of Christ''s passion; the persecutor becomes the persecuted. 2 Corinthians 11:23-28 is the syllabus foretold here.',
   'Christian ministry is not freed from suffering but conscripted into it. To bear Christ''s name is to bear Christ''s wounds; the cruciform pattern is the shape of all authentic apostolic labor.'),
  (17, 'And Ananias went his way, and entered into the house; and putting his hands on him said, Brother Saul, the Lord, even Jesus, that appeared unto thee in the way as thou camest, hath sent me, that thou mightest receive thy sight, and be filled with the Holy Ghost.',
   'ἀπῆλθεν δὲ Ἁνανίας καὶ εἰσῆλθεν εἰς τὴν οἰκίαν, καὶ ἐπιθεὶς ἐπ’ αὐτὸν τὰς χεῖρας εἶπεν· Σαοὺλ ἀδελφέ, ὁ κύριος ἀπέσταλκέν με, Ἰησοῦς ὁ ὀφθείς σοι ἐν τῇ ὁδῷ ᾗ ἤρχου, ὅπως ἀναβλέψῃς καὶ πλησθῇς πνεύματος ἁγίου.',
   'Apēlthen de Hananias kai eisēlthen eis tēn oikian, kai epitheis ep'' auton tas cheiras eipen; Saoul adelphe, ho kyrios apestalken me, Iēsous ho ophtheis soi en tē hodō hē ērchou, hopōs anablepsēs kai plēsthēs pneumatos hagiou.',
   '"Saoul adelphe" ("Brother Saul") — a single word crystallizes the grace of the gospel. The chief persecutor is received as brother; the Damascus disciples not only withhold revenge but bestow familial welcome. Note the unusual Spirit baptism order: Saul is filled before water baptism (v.18), contrary to the typical Acts sequence.',
   'Christian brotherhood is deeper than personal history or prior enmity. The Spirit creates a fellowship that pardons what it remembers and names the former enemy "brother."'),
  (18, 'And immediately there fell from his eyes as it had been scales: and he received sight forthwith, and arose, and was baptized.',
   'καὶ εὐθέως ἀπέπεσον αὐτοῦ ἀπὸ τῶν ὀφθαλμῶν ὡς λεπίδες, ἀνέβλεψέν τε, καὶ ἀναστὰς ἐβαπτίσθη,',
   'Kai eutheōs apepeson autou apo tōn ophthalmōn hōs lepides, aneblepsen te, kai anastas ebaptisthē,',
   '"Lepides" ("scales") is a medical term — Luke the physician''s precision — describing the crust of ophthalmic damage. Physical and spiritual sight are restored in the same moment. Saul''s baptism, without delay, embodies the pattern of Acts: conversion and public identification with Christ are not separated.',
   'Genuine conversion produces immediate, public, visible obedience. The new believer does not linger in private deliberation but rises, confesses, and is baptized — the body answers the new sight.'),
  (19, 'And when he had received meat, he was strengthened. Then was Saul certain days with the disciples which were at Damascus.',
   'καὶ λαβὼν τροφὴν ἐνίσχυσεν. ἐγένετο δὲ μετὰ τῶν ἐν Δαμασκῷ μαθητῶν ἡμέρας τινάς.',
   'Kai labōn trophēn enischysen. Egeneto de meta tōn en Damaskō mathētōn hēmeras tinas.',
   'Resumption of food follows baptism — the fast ends with communion. "Hēmeras tinas" ("certain days") is ambiguous here but complemented by Galatians 1:17-18, where Paul spends three years including time in Arabia before the Jerusalem visit. Luke compresses; Paul himself supplies the chronology.',
   'Christian growth presupposes ordinary fellowship: food, rest, and companionship with other disciples. Conversion launches not into heroic solitude but into the regular table-life of the church.'),
  (20, 'And straightway he preached Christ in the synagogues, that he is the Son of God.',
   'καὶ εὐθέως ἐν ταῖς συναγωγαῖς ἐκήρυσσεν τὸν Ἰησοῦν ὅτι οὗτός ἐστιν ὁ υἱὸς τοῦ θεοῦ.',
   'Kai eutheōs en tais synagōgais ekēryssen ton Iēsoun hoti houtos estin ho huios tou theou.',
   'The TR has "Christ" where the critical texts read "Jesus"; either way the confession is the same. "Huios tou theou" ("Son of God") is the only occurrence of this title on Paul''s lips in Acts, but it dominates his epistles (Rom 1:3-4; Gal 2:20). Saul''s first sermon thus announces the deity of Christ in the very synagogues he came to purge.',
   'The content of Christian preaching is the divine Sonship of Jesus. Anything less than the full deity of the Son is a different gospel; Saul begins where every Christian minister must begin, with the exalted identity of the risen Lord.'),
  (21, 'But all that heard him were amazed, and said; Is not this he that destroyed them which called on this name in Jerusalem, and came hither for that intent, that he might bring them bound unto the chief priests?',
   'ἐξίσταντο δὲ πάντες οἱ ἀκούοντες καὶ ἔλεγον· οὐχ οὗτός ἐστιν ὁ πορθήσας εἰς Ἰερουσαλὴμ τοὺς ἐπικαλουμένους τὸ ὄνομα τοῦτο, καὶ ὧδε εἰς τοῦτο ἐληλύθει ἵνα δεδεμένους αὐτοὺς ἀγάγῃ ἐπὶ τοὺς ἀρχιερεῖς;',
   'Existanto de pantes hoi akouontes kai elegon; ouch houtos estin ho porthēsas eis Ierousalēm tous epikaloumenous to onoma touto, kai hōde eis touto elēlythei hina dedemenous autous agagē epi tous archiereis?',
   '"Porthēsas" ("who destroyed, ravaged") — same verb Paul himself uses in Galatians 1:13, 23. Saul''s reputation and reversal were the talk of both Damascus and Jerusalem.',
   'A transformed life is its own apologetic. The crowd''s astonishment is the evidence; when the persecutor preaches, the gospel is self-attestingly true.'),
  (22, 'But Saul increased the more in strength, and confounded the Jews which dwelt at Damascus, proving that this is very Christ.',
   'Σαῦλος δὲ μᾶλλον ἐνεδυναμοῦτο καὶ συνέχυννεν τοὺς Ἰουδαίους τοὺς κατοικοῦντας ἐν Δαμασκῷ, συμβιβάζων ὅτι οὗτός ἐστιν ὁ χριστός.',
   'Saulos de mallon enedynamouto kai synechynnen tous Ioudaious tous katoikountas en Damaskō, symbibazōn hoti houtos estin ho christos.',
   '"Symbibazōn" ("proving, drawing together") describes reasoned demonstration from Scripture — Saul rapidly develops the Christ-centered hermeneutic later unpacked in his epistles. "Enedynamouto" ("was empowered") is a divine passive: the Spirit continually strengthens the new apostle.',
   'Apostolic preaching is rigorous biblical argument, not mere testimony. The Christian who proclaims must also reason from the Scriptures, showing that Jesus of Nazareth is the promised Messiah.'),
  (23, 'And after that many days were fulfilled, the Jews took counsel to kill him:',
   'ὡς δὲ ἐπληροῦντο ἡμέραι ἱκαναί, συνεβουλεύσαντο οἱ Ἰουδαῖοι ἀνελεῖν αὐτόν·',
   'Hōs de eplērounto hēmerai hikanai, synebouleusanto hoi Ioudaioi anelein auton;',
   '"Hēmerai hikanai" ("many days") likely encompasses the three-year period of Galatians 1:17-18, including Paul''s Arabia retreat. The Damascus synagogue that had issued him letters now plots his death — the persecutor''s method turned upon him.',
   'Those who once applauded the servant of God for opposing his people often turn upon him when he becomes their brother. The measure of sword is often drawn from the scabbard its wielders forged.'),
  (24, 'But their laying await was known of Saul. And they watched the gates day and night to kill him.',
   'ἐγνώσθη δὲ τῷ Σαύλῳ ἡ ἐπιβουλὴ αὐτῶν. παρετηροῦντο δὲ καὶ τὰς πύλας ἡμέρας τε καὶ νυκτὸς ὅπως αὐτὸν ἀνέλωσιν·',
   'Egnōsthē de tō Saulō hē epiboulē autōn. Paretērounto de kai tas pylas hēmeras te kai nyktos hopōs auton anelōsin;',
   '2 Corinthians 11:32 adds the detail that "the governor under Aretas the king" cooperated in the watch — the ethnarch of Nabatean Damascus combined with the Jewish leadership to seal the gates.',
   'God''s providence protects his servants through the awareness he grants them of danger. Apostolic courage is not recklessness; knowing the plot, Saul escapes to serve another day.'),
  (25, 'Then the disciples took him by night, and let him down by the wall in a basket.',
   'λαβόντες δὲ οἱ μαθηταὶ αὐτοῦ νυκτὸς διὰ τοῦ τείχους καθῆκαν αὐτὸν χαλάσαντες ἐν σπυρίδι.',
   'Labontes de hoi mathētai autou nyktos dia tou teichous kathēkan auton chalasantes en spyridi.',
   '"Spyris" is a large woven basket, the same word used of the seven baskets at the feeding of the 4,000 (Matt 15:37). Paul himself recalls this humiliation ("was I let down by the wall in a basket," 2 Cor 11:33) as a charter memory of apostolic weakness.',
   'God''s glory is revealed in vulnerable deliverances. The great apostle begins his ministry not on horseback but in a basket; the servant of Christ must learn to boast in weakness from the start.'),
  (26, 'And when Saul was come to Jerusalem, he assayed to join himself to the disciples: but they were all afraid of him, and believed not that he was a disciple.',
   'Παραγενόμενος δὲ εἰς Ἰερουσαλὴμ ἐπείραζεν κολλᾶσθαι τοῖς μαθηταῖς· καὶ πάντες ἐφοβοῦντο αὐτόν, μὴ πιστεύοντες ὅτι ἐστὶν μαθητής.',
   'Paragenomenos de eis Ierousalēm epeirazen kollasthai tois mathētais; kai pantes ephobounto auton, mē pisteuontes hoti estin mathētēs.',
   '"Epeirazen kollasthai" ("he attempted to join himself") — the imperfect signals repeated, unsuccessful efforts. "Kollaō" is strong verb, "to glue, bond." Three years on from Damascus, the Jerusalem church still remembers the raiding Pharisee.',
   'Even genuine converts may face prolonged ecclesial skepticism. The church''s due caution against false profession is not itself a failure of charity; but the Spirit will always eventually vindicate his own.'),
  (27, 'But Barnabas took him, and brought him to the apostles, and declared unto them how he had seen the Lord in the way, and that he had spoken to him, and how he had preached boldly at Damascus in the name of Jesus.',
   'Βαρναβᾶς δὲ ἐπιλαβόμενος αὐτὸν ἤγαγεν πρὸς τοὺς ἀποστόλους, καὶ διηγήσατο αὐτοῖς πῶς ἐν τῇ ὁδῷ εἶδεν τὸν κύριον καὶ ὅτι ἐλάλησεν αὐτῷ, καὶ πῶς ἐν Δαμασκῷ ἐπαρρησιάσατο ἐν τῷ ὀνόματι τοῦ Ἰησοῦ.',
   'Barnabas de epilabomenos auton ēgagen pros tous apostolous, kai diēgēsato autois pōs en tē hodō eiden ton kyrion kai hoti elalēsen autō, kai pōs en Damaskō eparrēsiasato en tō onomati tou Iēsou.',
   '"Barnabas" (4:36) lives up to his "Son of Encouragement" name. Galatians 1:18-19 specifies that the apostles met by Saul were Peter and James the Lord''s brother. Barnabas'' mediation changes the course of Christian history: the Gentile mission hinges on one man''s willingness to vouch for another.',
   'Christian fellowship is mediated by trusted bridge-builders. The ministry of encouragement and personal vouching is not a minor gift but a strategic office in the body of Christ.'),
  (28, 'And he was with them coming in and going out at Jerusalem.',
   'καὶ ἦν μετ’ αὐτῶν εἰσπορευόμενος καὶ ἐκπορευόμενος εἰς Ἰερουσαλήμ, παρρησιαζόμενος ἐν τῷ ὀνόματι τοῦ κυρίου,',
   'Kai ēn met'' autōn eisporeuomenos kai ekporeuomenos eis Ierousalēm, parrēsiazomenos en tō onomati tou kyriou,',
   'The Hebraism "going in and out" denotes full fellowship and participation (cf. John 10:9). Saul now belongs in the very city he terrorized; the imperfects picture settled, ongoing life with the apostles.',
   'Conversion brings integration into the settled life of the local church. The mark of genuine faith is not spectacular isolation but ordinary, unremarkable belonging to the fellowship of believers.'),
  (29, 'And he spake boldly in the name of the Lord Jesus, and disputed against the Grecians: but they went about to slay him.',
   'ἐλάλει τε καὶ συνεζήτει πρὸς τοὺς Ἑλληνιστάς· οἱ δὲ ἐπεχείρουν ἀνελεῖν αὐτόν.',
   'Elalei te kai synezētei pros tous Hellēnistas; hoi de epecheiroun anelein auton.',
   '"Hellēnistas" are the Greek-speaking Jews — the very constituency Saul represented at Stephen''s dispute (6:9). He now stands in Stephen''s place, arguing the same cause and facing the same lethal response. Divine irony is exact.',
   'God often repurposes the gifted former enemy to fulfill the very ministry he tried to suppress. Saul completes Stephen''s witness in Stephen''s forum, showing that martyrdom''s seed is never lost.'),
  (30, 'Which when the brethren knew, they brought him down to Caesarea, and sent him forth to Tarsus.',
   'ἐπιγνόντες δὲ οἱ ἀδελφοὶ κατήγαγον αὐτὸν εἰς Καισάρειαν καὶ ἐξαπέστειλαν αὐτὸν εἰς Ταρσόν.',
   'Epignontes de hoi adelphoi katēgagon auton eis Kaisareian kai exapesteilan auton eis Tarson.',
   'Caesarea (Maritima) was the provincial capital with the major port; from there Saul sails home to Tarsus of Cilicia, his native city. Paul''s "hidden years" (c. AD 36-45) occur here before Barnabas retrieves him (11:25-26). God hides his instruments until the appointed hour.',
   'Seasons of apparent obscurity are part of the divine curriculum. God prepares his most effective servants in silence before he deploys them; fruitful years in the spotlight are often preceded by hidden years in the shadow.'),
  (31, 'Then had the churches rest throughout all Judaea and Galilee and Samaria, and were edified; and walking in the fear of the Lord, and in the comfort of the Holy Ghost, were multiplied.',
   'Ἡ μὲν οὖν ἐκκλησία καθ’ ὅλης τῆς Ἰουδαίας καὶ Γαλιλαίας καὶ Σαμαρείας εἶχεν εἰρήνην οἰκοδομουμένη, καὶ πορευομένη τῷ φόβῳ τοῦ κυρίου καὶ τῇ παρακλήσει τοῦ ἁγίου πνεύματος ἐπληθύνετο.',
   'Hē men oun ekklēsia kath'' holēs tēs Ioudaias kai Galilaias kai Samareias eichen eirēnēn oikodomoumenē, kai poreuomenē tō phobō tou kyriou kai tē paraklēsei tou hagiou pneumatos eplēthyneto.',
   'Luke''s first "ekklēsia" in the singular over a regional scope (Judea, Galilee, Samaria together). Four blessings follow peace: edification, fear of the Lord, comfort of the Holy Spirit, and numerical multiplication. Peace is not stagnation; rest begets growth.',
   'Seasons of peace are God''s gift for strengthening; the healthy church uses calm to deepen foundations and extend reach. Rest in God never produces inertia but always greater fruitfulness in the Spirit.'),
  (32, 'And it came to pass, as Peter passed throughout all quarters, he came down also to the saints which dwelt at Lydda.',
   'Ἐγένετο δὲ Πέτρον διερχόμενον διὰ πάντων κατελθεῖν καὶ πρὸς τοὺς ἁγίους τοὺς κατοικοῦντας Λύδδα.',
   'Egeneto de Petron dierchomenon dia pantōn katelthein kai pros tous hagious tous katoikountas Lydda.',
   'Lydda (OT Lod, modern Lod near Tel Aviv) lies on the coastal plain about 25 miles NW of Jerusalem. Luke now rejoins Peter''s itinerancy — the Jerusalem apostles are not cloistered but visiting the regional congregations. The narrative geographically migrates toward the Gentile breakthrough in Caesarea (ch. 10).',
   'Pastoral visitation of scattered congregations is an apostolic pattern. Leadership that stays in the mother church and never touches the regional churches fails the flock Christ has entrusted.'),
  (33, 'And there he found a certain man named Aeneas, which had kept his bed eight years, and was sick of the palsy.',
   'εὗρεν δὲ ἐκεῖ ἄνθρωπόν τινα ὀνόματι Αἰνέαν ἐξ ἐτῶν ὀκτὼ κατακείμενον ἐπὶ κραβάττου, ὃς ἦν παραλελυμένος.',
   'Heuren de ekei anthrōpon tina onomati Ainean ex etōn oktō katakeimenon epi krabattou, hos ēn paralelymenos.',
   '"Aineas" (a Greek name) may have been a Gentile or Hellenistic Jew — Luke does not explicitly class him among the "saints." "Paralelymenos" ("paralyzed") is Luke''s medical term. Eight years bedridden signals a chronic, apparently incurable condition.',
   'God specializes in conditions declared hopeless by human expertise. The longer the bondage, the greater the glory of the deliverance; chronic need is the arena of revealed omnipotence.'),
  (34, 'And Peter said unto him, Aeneas, Jesus Christ maketh thee whole: arise, and make thy bed. And he arose immediately.',
   'καὶ εἶπεν αὐτῷ ὁ Πέτρος· Αἰνέα, ἰᾶταί σε Ἰησοῦς Χριστός· ἀνάστηθι καὶ στρῶσον σεαυτῷ. καὶ εὐθέως ἀνέστη.',
   'Kai eipen autō ho Petros; Ainea, iatai se Iēsous Christos; anastēthi kai strōson seautō. Kai eutheōs anestē.',
   '"Iatai" ("heals") — present tense: Jesus is the present, active healer; Peter is only the voice. The command "strōson seautō" ("make thy bed for thyself") signals the completeness of restoration and the dismissal of invalidity.',
   'Apostolic healings are acts of the risen Christ, mediated through his servants. Peter speaks no incantation; he names the Name. All genuine ministry points beyond the minister to the Healer.'),
  (35, 'And all that dwelt at Lydda and Saron saw him, and turned to the Lord.',
   'καὶ εἶδον αὐτὸν πάντες οἱ κατοικοῦντες Λύδδα καὶ τὸν Σαρῶνα, οἵτινες ἐπέστρεψαν ἐπὶ τὸν κύριον.',
   'Kai eidon auton pantes hoi katoikountes Lydda kai ton Sarōna, hoitines epestrepsan epi ton kyrion.',
   '"Ton Sarōna" — the fertile coastal plain of Sharon (cf. Isa 35:2; Song 2:1). Luke''s hyperbolic "pantes" ("all") signals widespread regional turning. "Epestrepsan" ("turned") is the characteristic Lukan verb of conversion.',
   'Authentic miracles lead not to celebrity but to conversion to Christ. A sign that draws attention to the sign-worker has failed; a sign that draws whole regions to the Lord has succeeded.'),
  (36, 'Now there was at Joppa a certain disciple named Tabitha, which by interpretation is called Dorcas: this woman was full of good works and almsdeeds which she did.',
   'Ἐν Ἰόππῃ δέ τις ἦν μαθήτρια ὀνόματι Ταβιθά, ἣ διερμηνευομένη λέγεται Δορκάς· αὕτη ἦν πλήρης ἔργων ἀγαθῶν καὶ ἐλεημοσυνῶν ὧν ἐποίει.',
   'En Ioppē de tis ēn mathētria onomati Tabitha, hē diermēneuomenē legetai Dorkas; hautē ēn plērēs ergōn agathōn kai eleēmosynōn hōn epoiei.',
   '"Mathētria" ("disciple" — feminine) is the only NT occurrence of the feminine form, quietly but explicitly certifying the church''s recognition of women disciples. Both Aramaic (Tabitha) and Greek (Dorcas) names mean "gazelle." Her CV is not office or eloquence but "good works and almsdeeds."',
   'Christ''s church includes the inconspicuously generous. The highest praise of a believer in Acts is "full of good works and almsdeeds" — a life spent in tangible mercy becomes the resumé God preserves.'),
  (37, 'And it came to pass in those days, that she was sick, and died: whom when they had washed, they laid her in an upper chamber.',
   'ἐγένετο δὲ ἐν ταῖς ἡμέραις ἐκείναις ἀσθενήσασαν αὐτὴν ἀποθανεῖν· λούσαντες δὲ αὐτὴν ἔθηκαν ἐν ὑπερῴῳ.',
   'Egeneto de en tais hēmerais ekeinais asthenēsasan autēn apothanein; lousantes de autēn ethēkan en hyperōō.',
   'The body is washed according to Jewish custom but not yet anointed for burial — the disciples seem to hold space for hope. The upper chamber recalls the Elisha–Shunammite miracle (2 Kgs 4) and anticipates Peter''s act.',
   'Christian hope does not erase grief but carries mourning toward the possibility of resurrection. The disciples prepare for burial yet summon Peter — faith does not deny death but looks for the God who raises the dead.'),
  (38, 'And forasmuch as Lydda was nigh to Joppa, and the disciples had heard that Peter was there, they sent unto him two men, desiring him that he would not delay to come to them.',
   'ἐγγὺς δὲ οὔσης Λύδδης τῇ Ἰόππῃ οἱ μαθηταὶ ἀκούσαντες ὅτι Πέτρος ἐστὶν ἐν αὐτῇ ἀπέστειλαν δύο ἄνδρας πρὸς αὐτὸν παρακαλοῦντες· μὴ ὀκνήσῃς διελθεῖν ἕως ἡμῶν.',
   'Engys de ousēs Lyddēs tē Ioppē hoi mathētai akousantes hoti Petros estin en autē apesteilan dyo andras pros auton parakalountes; mē oknēsēs dielthein heōs hēmōn.',
   'Lydda to Joppa is about 12 miles. Two messengers are sent (cf. Jesus'' commissioning pairs, Mark 6:7); Peter''s proximity and the urgency are both emphasized. The Joppa disciples act in concrete hope.',
   'Prayer and human effort are not opposed but wedded. The saints at Joppa both washed the body and sent for Peter; trust in God does not exclude deploying every proper means.'),
  (39, 'Then Peter arose and went with them. When he was come, they brought him into the upper chamber: and all the widows stood by him weeping, and shewing the coats and garments which Dorcas made, while she was with them.',
   'ἀναστὰς δὲ Πέτρος συνῆλθεν αὐτοῖς· ὃν παραγενόμενον ἀνήγαγον εἰς τὸ ὑπερῷον, καὶ παρέστησαν αὐτῷ πᾶσαι αἱ χῆραι κλαίουσαι καὶ ἐπιδεικνύμεναι χιτῶνας καὶ ἱμάτια ὅσα ἐποίει μετ’ αὐτῶν οὖσα ἡ Δορκάς.',
   'Anastas de Petros synēlthen autois; hon paragenomenon anēgagon eis to hyperōon, kai parestēsan autō pasai hai chērai klaiousai kai epideiknymenai chitōnas kai himatia hosa epoiei met'' autōn ousa hē Dorkas.',
   'The widows (a defined church constituency, cf. 6:1; 1 Tim 5) model lament as evidence: they display Dorcas''s handiwork. The scene presents the theology of good works — enduring, tangible, specific — as the best eulogy.',
   'Widows and the poor will eulogize the believer whose life was spent in their service. The final evidence of grace is not eloquence or doctrine alone but clothes stitched, meals given, bodies warmed.'),
  (40, 'But Peter put them all forth, and kneeled down, and prayed; and turning him to the body said, Tabitha, arise. And she opened her eyes: and when she saw Peter, she sat up.',
   'ἐκβαλὼν δὲ ἔξω πάντας ὁ Πέτρος καὶ θεὶς τὰ γόνατα προσηύξατο, καὶ ἐπιστρέψας πρὸς τὸ σῶμα εἶπεν· Ταβιθά, ἀνάστηθι. ἡ δὲ ἤνοιξεν τοὺς ὀφθαλμοὺς αὐτῆς, καὶ ἰδοῦσα τὸν Πέτρον ἀνεκάθισεν.',
   'Ekbalōn de exō pantas ho Petros kai theis ta gonata prosēuxato, kai epistrepsas pros to sōma eipen; Tabitha, anastēthi. Hē de ēnoixen tous ophthalmous autēs, kai idousa ton Petron anekathisen.',
   'Peter echoes Jesus'' raising of Jairus''s daughter (Mark 5:40-41; "Talitha cumi" — note one letter difference from "Tabitha qumi"). Peter kneels first (unlike Jesus, who stood) — apostles work in the power of Another. The scene is the first raising-from-the-dead in Acts and confirms continuity with Christ''s own ministry.',
   'Resurrection power is exercised through prayer in Jesus'' name, never through independent apostolic authority. Peter prays first, then commands — the derivative nature of Christian ministry is embedded in the posture itself.'),
  (41, 'And he gave her his hand, and lifted her up, and when he had called the saints and widows, presented her alive.',
   'δοὺς δὲ αὐτῇ χεῖρα ἀνέστησεν αὐτήν, φωνήσας δὲ τοὺς ἁγίους καὶ τὰς χήρας παρέστησεν αὐτὴν ζῶσαν.',
   'Dous de autē cheira anestēsen autēn, phōnēsas de tous hagious kai tas chēras parestēsen autēn zōsan.',
   '"Parestēsen… zōsan" ("he presented her alive") is the vocabulary of apostolic witness (cf. 1:3, "he shewed himself alive"). Peter returns Dorcas to the community visibly restored, for the consolation and faith-building of the whole church.',
   'Resurrection is never for the individual alone. Every act of saving grace is a restoration to the fellowship of the saints; Christ raises us to one another as well as to himself.'),
  (42, 'And it was known throughout all Joppa; and many believed in the Lord.',
   'γνωστὸν δὲ ἐγένετο καθ’ ὅλης τῆς Ἰόππης, καὶ ἐπίστευσαν πολλοὶ ἐπὶ τὸν κύριον.',
   'Gnōston de egeneto kath'' holēs tēs Ioppēs, kai episteusan polloi epi ton kyrion.',
   'The news spreads "kath'' holēs tēs Ioppēs" — across the whole port city. As with Aeneas at Lydda/Sharon, the miracle''s effect is evangelistic conversion, not mere amazement.',
   'The true fruit of miracles is faith in the Lord. Signs and wonders are never self-justifying; their God-intended issue is people placing trust in Christ.'),
  (43, 'And it came to pass, that he tarried many days in Joppa with one Simon a tanner.',
   'Ἐγένετο δὲ ἡμέρας ἱκανὰς μεῖναι ἐν Ἰόππῃ παρά τινι Σίμωνι βυρσεῖ.',
   'Egeneto de hēmeras hikanas meinai en Ioppē para tini Simōni byrsei.',
   '"Byrseus" ("tanner") is a trade regarded as ritually unclean by stricter Pharisaic interpretation because of constant contact with dead animals. Peter, formerly a strict Jew, now lodges freely with a tanner — a small but telling preparation for the Cornelius breakthrough (ch. 10) that is about to redraw the clean/unclean categories altogether.',
   'God often prepares his servants for great transitions through quiet, prior concessions. Peter''s ease with a tanner is the domestic rehearsal for the theological revolution he is about to witness among the Gentiles.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 9
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

-- 3. Word studies
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐμπνέων', 'empneōn', 'G1709', 'Present participle of empneō, "to breathe in/out, inspire." Saul ''inhales'' threat and murder as his native atmosphere.', 1),
  (1, 'ἀπειλῆς', 'apeilēs', 'G547', 'Threat, menace. Denotes the hostile rhetoric of intimidation that preceded arrest.', 2),
  (2, 'τῆς ὁδοῦ', 'tēs hodou', 'G3598', 'The Way. Earliest self-designation of Christians, rooted in Jesus as "the way" (John 14:6); six occurrences in Acts.', 3),
  (3, 'περιήστραψεν', 'periēstrapsen', 'G4015', 'Flashed around, enveloped in light. Cognate with astrapē (lightning); denotes theophanic brightness.', 4),
  (4, 'διώκεις', 'diōkeis', 'G1377', 'Pursue, persecute. The verb of forensic chase; Jesus identifies himself as the direct object of Saul''s hostility.', 5),
  (5, 'κύριε', 'kyrie', 'G2962', 'Lord, sir, master. Title of divine address; the word for Yahweh in the Septuagint, now owned by Jesus.', 6),
  (6, 'δεῖ', 'dei', 'G1163', 'It is necessary. Lukan verb of divine decree; punctuates the providential ''must'' of redemptive history.', 7),
  (7, 'ἐνεοί', 'eneoi', 'G1769', 'Speechless, dumbstruck. Rare term conveying awed paralysis of speech.', 8),
  (8, 'χειραγωγοῦντες', 'cheiragōgountes', 'G5496', 'Leading by the hand. Poignant image of apostolic reversal: the arrester now needs a guide.', 9),
  (10, 'μαθητής', 'mathētēs', 'G3101', 'Disciple, learner. Standard Acts term for believer; Ananias is defined by discipleship alone.', 10),
  (11, 'προσεύχεται', 'proseuchetai', 'G4336', 'Is praying. First evidence of Saul''s conversion; the Spirit''s work in the interior is auditable by God alone.', 11),
  (14, 'ἐπικαλουμένους', 'epikaloumenous', 'G1941', 'Calling upon, invoking. Technical term for prayerful worship; Christians are defined as those who pray to Jesus.', 12),
  (15, 'σκεῦος', 'skeuos', 'G4632', 'Vessel, instrument. God''s chosen means, a container for divine purpose (cf. Rom 9:21-23).', 13),
  (15, 'ἐκλογῆς', 'eklogēs', 'G1589', 'Election, choosing. Denotes divine selection for a task; genitive of definition—Saul is a ''vessel belonging to election.''', 14),
  (15, 'βαστάσαι', 'bastasai', 'G941', 'To bear, carry. Paul will literally carry Christ''s name across the Mediterranean basin.', 15),
  (15, 'ἐθνῶν', 'ethnōn', 'G1484', 'Nations, Gentiles. Paul''s primary mission field; first in Luke''s triadic list.', 16),
  (16, 'παθεῖν', 'pathein', 'G3958', 'To suffer. Passion-vocabulary now applied to Paul; the cross-pattern defines his ministry.', 17),
  (17, 'ἀδελφέ', 'adelphe', 'G80', 'Brother. Ananias''s first word to Saul; grace-laden reclassification of the former enemy.', 18),
  (18, 'λεπίδες', 'lepides', 'G3013', 'Scales, flakes. Medical language (Luke as physician); literal and symbolic removal of blindness.', 19),
  (19, 'ἐνίσχυσεν', 'enischysen', 'G1765', 'Was strengthened. Physical recovery mirroring spiritual empowerment.', 20),
  (20, 'ἐκήρυσσεν', 'ekēryssen', 'G2784', 'Was proclaiming. Imperfect—ongoing heraldic announcement; the same verb used of apostolic preaching.', 21),
  (22, 'ἐνεδυναμοῦτο', 'enedynamouto', 'G1743', 'Was being empowered. Divine passive; the same verb Paul later uses ("I can do all things…," Phil 4:13).', 22),
  (22, 'συμβιβάζων', 'symbibazōn', 'G4822', 'Joining together, proving. Connotes reasoned demonstration that knits Scripture to Christ.', 23),
  (27, 'ἐπαρρησιάσατο', 'eparrēsiasato', 'G3955', 'Spoke boldly, with frankness. Parrēsia is a hallmark virtue of Acts preaching.', 24),
  (31, 'οἰκοδομουμένη', 'oikodomoumenē', 'G3618', 'Being built up. Present passive; edification is continuous and received.', 25),
  (31, 'παρακλήσει', 'paraklēsei', 'G3874', 'Comfort, encouragement, exhortation. The Spirit''s ministry of strengthening the church.', 26),
  (34, 'ἰᾶταί', 'iatai', 'G2390', 'Heals (present tense). The risen Christ is the continuing active Healer; Peter is only the voice.', 27),
  (35, 'ἐπέστρεψαν', 'epestrepsan', 'G1994', 'They turned. Conversion as reorientation; the characteristic Lukan verb of repentance.', 28),
  (36, 'μαθήτρια', 'mathētria', 'G3102', 'Female disciple. Only NT occurrence; affirms women as full disciples.', 29),
  (36, 'ἐλεημοσυνῶν', 'eleēmosynōn', 'G1654', 'Alms, deeds of mercy. Tangible, merciful giving as the mark of a gospel-formed life.', 30),
  (40, 'ἀνάστηθι', 'anastēthi', 'G450', 'Arise. The resurrection imperative; same root used for Christ''s resurrection.', 31),
  (43, 'βυρσεῖ', 'byrsei', 'G1038', 'Tanner. A trade considered ceremonially unclean; Peter''s lodging with Simon anticipates the Cornelius breakthrough.', 32)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 9 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

-- 4. Cross references
INSERT INTO cross_references (verse_id, reference, ref_order)
SELECT v.id, x.reference, x.ref_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Acts 8:3', 1),
  (1, 'Galatians 1:13', 2),
  (1, '1 Timothy 1:13', 3),
  (1, 'Philippians 3:6', 4),
  (2, 'Acts 19:9', 5),
  (2, 'Acts 22:4', 6),
  (2, 'Acts 24:14', 7),
  (2, 'John 14:6', 8),
  (3, '2 Corinthians 4:6', 9),
  (3, 'Acts 22:6', 10),
  (3, 'Acts 26:13', 11),
  (4, 'Matthew 25:40', 12),
  (4, 'Matthew 25:45', 13),
  (4, '1 Corinthians 12:12', 14),
  (4, 'Zechariah 2:8', 15),
  (4, 'Exodus 3:4', 16),
  (5, 'Acts 26:14', 17),
  (5, 'Acts 4:10', 18),
  (5, '1 Corinthians 15:8', 19),
  (6, 'Acts 22:10', 20),
  (6, 'Acts 26:16', 21),
  (7, 'Acts 22:9', 22),
